def solve(cyanobacterial_data):
    if not isinstance(cyanobacterial_data, list):
        raise ValueError("Input must be a list of cyanobacterial data.")

    if not all(isinstance(data, dict) for data in cyanobacterial_data):
        raise ValueError("Each item in the list must be a dictionary.")

    results = []
    for data in cyanobacterial_data:
        if 'location' not in data or 'level' not in data:
            raise ValueError("Each dictionary must contain 'location' and 'level' keys.")

        location = data['location']
        level = data['level']

        if not isinstance(location, str) or not isinstance(level, (int, float)):
            raise ValueError("Location must be a string and level must be a number.")

        if level > 100:
            results.append((location, "High risk"))
        elif level > 50:
            results.append((location, "Moderate risk"))
        else:
            results.append((location, "Low risk"))

    return results
